# VonB growth convergence ----
## Setup ----
make_vonb_convergence_context <- function() {
  data("data1", package = "FIMS")
  fims_frame <- FIMS::FIMSFrame(data1)

  configurations <- FIMS::create_default_configurations(data = fims_frame) |>
    tidyr::unnest(cols = data) |>
    dplyr::mutate(
      module_type = dplyr::if_else(
        module_name == "Growth",
        "VonBertalanffy",
        module_type
      )
    ) |>
    tidyr::nest(.by = c(model_family, module_name, fleet_name))

  parameters <- FIMS::create_default_parameters(
    configurations = configurations,
    data = fims_frame
  ) |>
    tidyr::unnest(cols = data) |>
    dplyr::mutate(
      estimation_type = dplyr::case_when(
        module_name == "Growth" &
          label %in% c(
            "length_at_ref_age_1",
            "length_at_ref_age_2",
            "growth_coefficient_K"
          ) ~ "fixed_effects",
        TRUE ~ "constant"
      )
    )

  list(
    data = fims_frame,
    parameters = parameters
  )
}

make_two_fleet_length_context <- function() {
  data("data1", package = "FIMS")
  survey1_short_bins <- seq(0, 550, 50)
  survey1_bins <- tibble::tibble(
    type = "length-bin",
    name = "survey1",
    age = NA_real_,
    length = survey1_short_bins,
    value = NA_real_,
    unit = unique(data1$unit[which(data1$name == "survey1")])[1],
    timing = min(data1$timing[data1$name == "survey1"], na.rm = TRUE),
    uncertainty = NA_real_
  )

  custom_data <- data1 |>
    dplyr::filter(
      !(
        .data[["name"]] == "survey1" &
          .data[["type"]] == "age-to-length-conversion"
      )
    ) |>
    dplyr::filter(
      !(
        .data[["name"]] == "survey1" &
          .data[["type"]] == "length_comp" &
          !is.na(.data[["length"]]) &
          !(.data[["length"]] %in% survey1_short_bins)
      )
    ) |>
    dplyr::bind_rows(survey1_bins)
  fims_frame <- FIMS::FIMSFrame(custom_data)

  configurations <- FIMS::create_default_configurations(data = fims_frame) |>
    tidyr::unnest(cols = data) |>
    dplyr::mutate(
      module_type = dplyr::if_else(
        module_name == "Growth",
        "VonBertalanffy",
        module_type
      )
    ) |>
    tidyr::nest(.by = c(model_family, module_name, fleet_name))

  parameters <- FIMS::create_default_parameters(
    configurations = configurations,
    data = fims_frame
  ) |>
    tidyr::unnest(cols = data)

  list(
    data = fims_frame,
    parameters = parameters
  )
}

make_default_growth_fixed_alk_context <- function() {
  data("data1", package = "FIMS")
  fims_frame <- FIMS::FIMSFrame(data1)

  parameters <- FIMS::create_default_configurations(data = fims_frame) |>
    FIMS::create_default_parameters(data = fims_frame) |>
    tidyr::unnest(cols = data)

  list(
    data = fims_frame,
    parameters = parameters
  )
}

make_vonb_model_comparison_context <- function() {
  data("data1", package = "FIMS")
  fims_frame <- FIMS::FIMSFrame(data1)

  # Start from the model comparison project parameter fixture for all
  # non-growth modules, then replace EWAA growth with VonB growth.
  base_parameters <- readRDS(
    testthat::test_path("fixtures", "parameters_model_comparison_project.RDS")
  ) |>
    dplyr::filter(module_name != "Growth")

  vonb_growth <- FIMS::create_default_configurations(data = fims_frame) |>
    tidyr::unnest(cols = data) |>
    dplyr::mutate(
      module_type = dplyr::if_else(
        module_name == "Growth",
        "VonBertalanffy",
        module_type
      )
    ) |>
    tidyr::nest(.by = c(model_family, module_name, fleet_name)) |>
    FIMS::create_default_parameters(data = fims_frame) |>
    tidyr::unnest(cols = data) |>
    dplyr::filter(module_name == "Growth")

  list(
    data = fims_frame,
    parameters = dplyr::bind_rows(base_parameters, vonb_growth)
  )
}

## IO correctness ----
test_that("von bertalanffy growth converges when L1 L2 and K are estimable", {
  ctx <- make_vonb_convergence_context()
  on.exit({ rm(ctx); gc() }, add = TRUE)

  input <- ctx$parameters |>
    FIMS::initialize_fims(data = ctx$data)
  input$model$ReportGrowthDerivedALKTensor(TRUE)

  fit <- FIMS::fit_fims(
    input = input,
    optimize = TRUE,
    get_sd = FALSE
  )

  opt <- FIMS::get_opt(fit)
  report <- FIMS::get_report(fit)
  growth_estimates <- FIMS::get_estimates(fit) |>
    dplyr::filter(module_name == "Growth")

  #' @description Test that the VonB growth fit converges normally.
  expect_equal(opt$convergence, 0)

  #' @description Test that the VonB growth fit reaches a small maximum gradient.
  expect_lte(FIMS::get_max_gradient(fit), 0.01)

  #' @description Test that the estimable VonB growth parameters remain finite and positive.
  expect_true(all(is.finite(growth_estimates$estimated)))
  expect_true(all(
    growth_estimates |>
      dplyr::filter(label %in% c(
        "length_at_ref_age_1",
        "length_at_ref_age_2",
        "growth_coefficient_K"
      )) |>
      dplyr::pull(estimated) > 0
  ))

  #' @description Test that the second reference length stays larger than the first.
  expect_gt(
    growth_estimates |>
      dplyr::filter(label == "length_at_ref_age_2") |>
      dplyr::pull(estimated),
    growth_estimates |>
      dplyr::filter(label == "length_at_ref_age_1") |>
      dplyr::pull(estimated)
  )

  #' @description Test that reported SD at length-at-age remains positive for the fitted VonB path.
  expect_true(all(
    report[["growth_sd_LAA"]][[1]] > 0
  ))

  #' @description Test that the fitted fleet reports using the growth-derived ALK path.
  expect_equal(
    report[["growth_derived_alk_used"]][[1]][1],
    1
  )

  #' @description Test that fixed age-to-length conversion remains available while the VonB path still selects growth-derived ALK.
  expect_gt(length(report[["age_to_length_conversion"]][[1]]), 0)

  #' @description Test that the fitted fleet reports finite growth-derived mean WAA when the dynamic ALK path is used.
  expect_true(all(is.finite(
    report[["growth_derived_mean_WAA"]][[1]]
  )))

  #' @description Test that population-level and fleet-level mean WAA agree for the supported single-fleet VonB path.
  expect_equal(
    report[["growth_mean_WAA"]][[1]],
    report[["growth_derived_mean_WAA"]][[1]],
    tolerance = 1e-8
  )

  #' @description Test that objective-side index weight-at-age uses the same fleet mean WAA as the derived VonB path.
  fleet_index_numbers_at_age <- report[["index_numbers_at_age"]][[1]]
  fleet_index_weight_at_age <- report[["index_weight_at_age"]][[1]]
  fleet_derived_mean_waa <- report[["growth_derived_mean_WAA"]][[1]]
  positive_index_cells <- abs(fleet_index_numbers_at_age) > 0
  expect_true(any(positive_index_cells))
  expect_equal(
    fleet_index_weight_at_age[positive_index_cells] /
      fleet_index_numbers_at_age[positive_index_cells],
    fleet_derived_mean_waa[positive_index_cells],
    tolerance = 1e-8
  )

  #' @description Test that objective-side landings weight-at-age uses the same fleet mean WAA as the derived VonB path.
  fleet_landings_numbers_at_age <- report[["landings_numbers_at_age"]][[1]]
  fleet_landings_weight_at_age <- report[["landings_weight_at_age"]][[1]]
  positive_landings_cells <- abs(fleet_landings_numbers_at_age) > 0
  expect_true(any(positive_landings_cells))
  expect_equal(
    fleet_landings_weight_at_age[positive_landings_cells] /
      fleet_landings_numbers_at_age[positive_landings_cells],
    fleet_derived_mean_waa[positive_landings_cells],
    tolerance = 1e-8
  )

  realized_alk <- report[["growth_derived_age_to_length_conversion"]][[1]]
  n_years <- FIMS::get_n_years(ctx$data)
  n_ages <- FIMS::get_n_ages(ctx$data)
  fleet1_obj <- FIMS:::initialize_module(
    parameters = ctx$parameters,
    data = ctx$data,
    module_name = "Fleet",
    fleet_name = "fleet1"
  )
  n_lengths <- fleet1_obj$n_lengths$get()
  realized_alk_array <- array(
    realized_alk,
    dim = c(n_lengths, n_ages, n_years)
  )

  #' @description Test that the realized growth-derived ALK rows sum to one for each year and age.
  expect_true(all(abs(apply(realized_alk_array, c(2, 3), sum) - 1) < 1e-5))

})

test_that("von bertalanffy growth estimates stay close to Model Comparison OM growth values", {
  ctx <- make_vonb_model_comparison_context()
  on.exit({ rm(ctx); gc() }, add = TRUE)

  # Model Comparison base-case OM values from save_initial_input.R
  Linf <- 800
  K <- 0.18
  a0 <- -1.36

  # Same VonB formula used in the model comparison OM and in data-raw/data1.R
  AtoL <- function(a, Linf, K, a0) {
    Linf * (1 - exp(-K * (a - a0)))
  }

  expected_growth <- tibble::tibble(
    label = c(
      "length_at_ref_age_1",
      "length_at_ref_age_2",
      "growth_coefficient_K"
    ),
    expected = c(
      AtoL(1, Linf, K, a0),
      AtoL(12, Linf, K, a0),
      K
    )
  )

  input <- ctx$parameters |>
    FIMS::initialize_fims(data = ctx$data)
  input$model$ReportGrowthDerivedALKTensor(TRUE)

  fit <- FIMS::fit_fims(
    input = input,
    optimize = TRUE,
    number_of_loops = 2,
    number_of_newton_steps = 0,
    get_sd = FALSE
  )

  #' @description Test that the VonB fit against Model Comparison OM values converges normally.
  expect_equal(FIMS::get_opt(fit)$convergence, 0)

  #' @description Test that the VonB fit against Model Comparison OM values reaches a small maximum gradient.
  expect_lte(FIMS::get_max_gradient(fit), 0.01)

  growth_estimates <- FIMS::get_estimates(fit) |>
    dplyr::filter(
      module_name == "Growth",
      label %in% expected_growth$label
    ) |>
    dplyr::select(label, estimated) |>
    dplyr::left_join(expected_growth, by = "label")

  #' @description Test that the fitted VonB output includes the three Model Comparison OM-truth growth parameters.
  expect_setequal(growth_estimates$label, expected_growth$label)

  #' @description Test that fitted length_at_ref_age_1 remains close to the model comparison OM value at age 1.
  expect_equal(
    growth_estimates |>
      dplyr::filter(label == "length_at_ref_age_1") |>
      dplyr::pull(estimated),
    growth_estimates |>
      dplyr::filter(label == "length_at_ref_age_1") |>
      dplyr::pull(expected),
    tolerance = 30
  )

  #' @description Test that fitted length_at_ref_age_2 remains close to the model comparison OM value at age 12.
  expect_equal(
    growth_estimates |>
      dplyr::filter(label == "length_at_ref_age_2") |>
      dplyr::pull(estimated),
    growth_estimates |>
      dplyr::filter(label == "length_at_ref_age_2") |>
      dplyr::pull(expected),
    tolerance = 30
  )

  #' @description Test that fitted growth_coefficient_K remains within 0.01 of the Model Comparison OM growth coefficient.
  expect_lte(
    abs(
      growth_estimates |>
        dplyr::filter(label == "growth_coefficient_K") |>
        dplyr::pull(estimated) -
        growth_estimates |>
        dplyr::filter(label == "growth_coefficient_K") |>
        dplyr::pull(expected)
    ),
    0.01
  )
})

test_that("von bertalanffy report defaults to lightweight derived ALK diagnostics", {
  ctx <- make_vonb_convergence_context()
  on.exit({ rm(ctx); gc() }, add = TRUE)

  fit <- ctx$parameters |>
    FIMS::initialize_fims(data = ctx$data) |>
    FIMS::fit_fims(optimize = FALSE)

  report <- FIMS::get_report(fit)

  #' @description Test that the derived VonB path is still selected in reports by default.
  expect_equal(report[["growth_derived_alk_used"]][[1]][1], 1)

  #' @description Test that default reporting keeps fleet growth-derived mean WAA available.
  expect_gt(length(report[["growth_derived_mean_WAA"]][[1]]), 0)

  #' @description Test that default reporting does not materialize the full derived ALK tensor.
  expect_equal(length(report[["growth_derived_age_to_length_conversion"]][[1]]), 0)
})

test_that("default non-derived growth keeps the historical fixed ALK path", {
  ctx <- make_default_growth_fixed_alk_context()
  on.exit({ rm(ctx); gc() }, add = TRUE)

  fit <- ctx$parameters |>
    FIMS::initialize_fims(data = ctx$data) |>
    FIMS::fit_fims(optimize = FALSE)

  report <- FIMS::get_report(fit)

  #' @description Test that the fixed age-to-length conversion matrix is present for the historical non-derived growth path.
  expect_gt(length(report[["age_to_length_conversion"]][[1]]), 0)

  #' @description Test that the non-derived growth path reports no growth-derived ALK usage.
  expect_equal(report[["growth_derived_alk_used"]][[1]][1], 0)

  #' @description Test that no realized growth-derived ALK tensor is produced for the fixed historical path.
  expect_equal(length(report[["growth_derived_age_to_length_conversion"]][[1]]), 0)
})

test_that("von bertalanffy Newton polishing does not worsen objective or gradient", {
  ctx <- make_vonb_convergence_context()
  on.exit({ rm(ctx); gc() }, add = TRUE)

  fit_base <- ctx$parameters |>
    FIMS::initialize_fims(data = ctx$data) |>
    FIMS::fit_fims(
      optimize = TRUE,
      get_sd = FALSE,
      number_of_newton_steps = 0
    )
  base_objective <- FIMS::get_opt(fit_base)$objective
  base_max_gradient <- FIMS::get_max_gradient(fit_base)
  rm(fit_base)
  gc()

  fit_newton <- ctx$parameters |>
    FIMS::initialize_fims(data = ctx$data) |>
    FIMS::fit_fims(
      optimize = TRUE,
      get_sd = FALSE,
      number_of_newton_steps = 1
    )
  newton_objective <- FIMS::get_opt(fit_newton)$objective
  newton_max_gradient <- FIMS::get_max_gradient(fit_newton)

  #' @description Test that optional Newton polishing does not worsen the optimized objective.
  expect_lte(
    newton_objective,
    base_objective + 1e-8
  )

  #' @description Test that optional Newton polishing does not worsen the maximum gradient.
  expect_lte(
    newton_max_gradient,
    base_max_gradient
  )
})

test_that("fleet-specific length bins initialize n_lengths consistently", {
  expect_no_warning(ctx <- make_two_fleet_length_context())
  on.exit({ rm(ctx); gc() }, add = TRUE)

  fleet1_obj <- FIMS:::initialize_module(
    parameters = ctx$parameters,
    data = ctx$data,
    module_name = "Fleet",
    fleet_name = "fleet1"
  )
  fleet_short_obj <- FIMS:::initialize_module(
    parameters = ctx$parameters,
    data = ctx$data,
    module_name = "Fleet",
    fleet_name = "survey1"
  )

  fleet1_lengths <- fleet1_obj$lengths$toRVector()
  fleet_short_lengths <- fleet_short_obj$lengths$toRVector()

  #' @description Test that each fleet's n_lengths matches its own initialized length-bin vector.
  expect_equal(fleet1_obj$n_lengths$get(), length(fleet1_lengths))
  expect_equal(fleet_short_obj$n_lengths$get(), length(fleet_short_lengths))

  #' @description Test that different fleets can carry different length-bin vectors.
  expect_false(identical(fleet1_lengths, fleet_short_lengths))
  expect_true(length(fleet_short_lengths) < length(fleet1_lengths))
  expect_equal(fleet_short_lengths, seq(0, 550, 50))

  lengthcomp1_obj <- FIMS:::initialize_comp(
    data = ctx$data,
    fleet_name = "fleet1",
    type = "LengthComp"
  )
  lengthcomp2_obj <- FIMS:::initialize_comp(
    data = ctx$data,
    fleet_name = "survey1",
    type = "LengthComp"
  )

  #' @description Test that each fleet's length-composition module matches its own length-comp data rows.
  expect_equal(
    lengthcomp1_obj$length_comp_data$toRVector(),
    ctx$data |>
      FIMS::get_data() |>
      dplyr::filter(type == "length_comp", name == "fleet1") |>
      dplyr::mutate(out = dplyr::if_else(is.na(value * uncertainty), -999, value * uncertainty)) |>
      dplyr::pull(out)
  )
  expect_equal(
    lengthcomp2_obj$length_comp_data$toRVector(),
    ctx$data |>
      FIMS::get_data() |>
      dplyr::filter(
        type == "length_comp",
        name == "survey1",
        length %in% fleet_short_lengths
      ) |>
      dplyr::mutate(out = dplyr::if_else(is.na(value * uncertainty), -999, value * uncertainty)) |>
      dplyr::pull(out)
  )
})

